import json
import os
from pathlib import Path
from typing import Optional

import pandas as pd


SOURCE_EXTENSION_TO_LANGUAGE = {
    ".c": "c",
    ".h": "c",
    ".cpp": "cpp",
    ".cc": "cpp",
    ".cxx": "cpp",
    ".hpp": "cpp",
    ".hxx": "cpp",
}
JAVA_CODE_COLUMNS = ("snippet", "scode", "code", "source", "content")


def _trim_files(files: list[str], max_files: Optional[int]) -> list[str]:
    if max_files is None:
        return files
    return files[:max_files]


def _append_row(rows: list[dict], row: dict, max_rows: Optional[int]) -> bool:
    rows.append(row)
    return max_rows is not None and len(rows) >= max_rows


def _load_jsonl_rows(file_path: str, rows: list[dict], max_rows: Optional[int]) -> bool:
    with open(file_path, "r", encoding="utf-8") as f:
        for line in f:
            obj = json.loads(line)
            should_stop = _append_row(
                rows,
                {
                    "code": obj.get("code", ""),
                    "docstring": obj.get("docstring", ""),
                    "repo": obj.get("repo", ""),
                    "path": obj.get("path", ""),
                    "language": obj.get("language", ""),
                },
                max_rows=max_rows,
            )
            if should_stop:
                return True
    return False


def _load_source_file_rows(file_path: str, rows: list[dict], max_rows: Optional[int]) -> bool:
    ext = Path(file_path).suffix.lower()
    language = SOURCE_EXTENSION_TO_LANGUAGE.get(ext)
    if not language:
        return False

    with open(file_path, "r", encoding="utf-8", errors="ignore") as f:
        code = f.read()

    return _append_row(
        rows,
        {
            "code": code,
            "docstring": "",
            "repo": "",
            "path": file_path,
            "language": language,
        },
        max_rows=max_rows,
    )


def _select_java_code_column(headers: list[str]) -> str | None:
    lookup = {h.strip().lower(): h for h in headers}
    for col in JAVA_CODE_COLUMNS:
        if col in lookup:
            return lookup[col]
    return None


def _load_java_csv_rows(file_path: str, rows: list[dict], max_rows: Optional[int]) -> bool:
    with open(file_path, "r", encoding="utf-8", newline="") as f:
        reader = csv.DictReader(f)
        if not reader.fieldnames:
            return False

        code_column = _select_java_code_column(reader.fieldnames)
        if not code_column:
            return False

        for index, record in enumerate(reader, start=1):
            code = str(record.get(code_column, "") or "")
            if not code.strip():
                continue

            should_stop = _append_row(
                rows,
                {
                    "code": code,
                    "docstring": "",
                    "repo": "",
                    "path": f"{file_path}#row{index}",
                    "language": "java",
                },
                max_rows=max_rows,
            )
            if should_stop:
                return True
    return False


def load_codesearchnet_data(
    folder_path: str,
    max_files: Optional[int] = None,
    max_rows: Optional[int] = None,
) -> pd.DataFrame:
    jsonl_files = _trim_files(
        sorted(glob.glob(os.path.join(folder_path, "**", "*.jsonl"), recursive=True)),
        max_files=max_files,
    )
    source_files = _trim_files(
        sorted(
            path
            for ext in SOURCE_EXTENSION_TO_LANGUAGE
            for path in glob.glob(os.path.join(folder_path, "**", f"*{ext}"), recursive=True)
        ),
        max_files=max_files,
    )
    java_csv_files = _trim_files(
        sorted(glob.glob(os.path.join(folder_path, "**", "*.csv"), recursive=True)),
        max_files=max_files,
    )

    print("Discovered dataset files:")
    print(f"- JSONL files: {len(jsonl_files)}")
    print(f"- C/C++ source files: {len(source_files)}")
    print(f"- CSV files: {len(java_csv_files)}")

    rows: list[dict] = []

    for file_path in jsonl_files:
        if _load_jsonl_rows(file_path, rows, max_rows=max_rows):
            return pd.DataFrame(rows)

    for file_path in source_files:
        if _load_source_file_rows(file_path, rows, max_rows=max_rows):
            return pd.DataFrame(rows)

    for file_path in java_csv_files:
        if _load_java_csv_rows(file_path, rows, max_rows=max_rows):
            return pd.DataFrame(rows)

    return pd.DataFrame(rows)

import ast
import re

import numpy as np


SUPPORTED_REVIEW_LANGUAGES = {"python", "c", "cpp", "java"}

LANGUAGE_ALIASES = {
    "py": "python",
    "c++": "cpp",
    "cc": "cpp",
    "cxx": "cpp",
    "hpp": "cpp",
    "hxx": "cpp",
}

EXTENSION_LANGUAGE_MAP = {
    "py": "python",
    "c": "c",
    "h": "c",
    "cpp": "cpp",
    "cxx": "cpp",
    "cc": "cpp",
    "hpp": "cpp",
    "java": "java",
}

FUNCTION_SIGNATURE_PATTERN = re.compile(
    r"^\s*"
    r"(?:(?:public|private|protected|static|final|virtual|inline|constexpr|friend|"
    r"synchronized|native|abstract)\s+)*"
    r"(?P<return_type>[\w:<>\[\],*&]+)"
    r"\s+"
    r"(?P<name>[A-Za-z_]\w*)"
    r"\s*\([^;{}]*\)"
    r"\s*(?P<brace>\{)?\s*$"
)

LOOP_PATTERN = re.compile(r"\b(?:for|while)\s*\(")
IF_PATTERN = re.compile(r"\bif\s*\(")
TRY_PATTERN = re.compile(r"\btry\s*\{")
DIVISION_BY_ZERO_PATTERN = re.compile(r"/\s*0(?:[^\d.]|$)")
INFINITE_LOOP_PATTERN = re.compile(r"\bwhile\s*\(\s*true\s*\)|\bfor\s*\(\s*;\s*;\s*\)")
MISSING_SEMICOLON_PATTERN = re.compile(r"^\s*return\b[^;{}]*$")

INPUT_PATTERNS = {
    "c": re.compile(r"\b(?:scanf|getchar|fgets|gets)\s*\("),
    "cpp": re.compile(r"\bcin\s*>>|\bgetline\s*\("),
    "java": re.compile(
        r"\.next(?:Int|Line|Double|Long|Float|Boolean|Short|Byte)\s*\(|\breadLine\s*\("
    ),
}

SORT_PATTERNS = {
    "c": re.compile(r"\bqsort\s*\("),
    "cpp": re.compile(r"\bsort\s*\("),
    "java": re.compile(r"\b(?:Arrays|Collections)\.sort\s*\("),
}

MEMORY_ALLOC_PATTERNS = {
    "c": re.compile(r"\b(?:malloc|calloc|realloc)\s*\("),
    "cpp": re.compile(r"\bnew\b"),
}

MEMORY_RELEASE_PATTERNS = {
    "c": re.compile(r"\bfree\s*\("),
    "cpp": re.compile(r"\bdelete\b"),
}

JAVA_RESOURCE_PATTERN = re.compile(
    r"\bnew\s+(?:Scanner|BufferedReader|FileInputStream|FileReader|InputStreamReader)\b"
)
JAVA_CLOSE_PATTERN = re.compile(r"\.close\s*\(")


def normalize_language(language):
    if not language:
        return None
    normalized = language.strip().lower()
    return LANGUAGE_ALIASES.get(normalized, normalized)


def detect_language_from_filename(filename):
    if not filename or "." not in filename:
        return None
    ext = filename.rsplit(".", 1)[-1].lower()
    return EXTENSION_LANGUAGE_MAP.get(ext)


def resolve_review_language(language=None, filename=None):
    normalized = normalize_language(language)
    if normalized in SUPPORTED_REVIEW_LANGUAGES:
        return normalized
    detected = detect_language_from_filename(filename)
    if detected in SUPPORTED_REVIEW_LANGUAGES:
        return detected
    return "python"


def strip_c_like_comments(code):
    code = re.sub(r"/\*.*?\*/", "", code, flags=re.S)
    return re.sub(r"//.*", "", code)


def basic_c_like_syntax_error(code):
    stack = []
    pairs = {")": "(", "]": "[", "}": "{"}
    state = "normal"
    line = 1
    escape = False
    i = 0

    while i < len(code):
        ch = code[i]
        nxt = code[i + 1] if i + 1 < len(code) else ""

        if state == "line_comment":
            if ch == "\n":
                state = "normal"
                line += 1
            i += 1
            continue

        if state == "block_comment":
            if ch == "*" and nxt == "/":
                state = "normal"
                i += 2
                continue
            if ch == "\n":
                line += 1
            i += 1
            continue

        if state in {"single_quote", "double_quote"}:
            if ch == "\n":
                line += 1
            if escape:
                escape = False
            elif ch == "\\":
                escape = True
            elif state == "single_quote" and ch == "'":
                state = "normal"
            elif state == "double_quote" and ch == '"':
                state = "normal"
            i += 1
            continue

        if ch == "/" and nxt == "/":
            state = "line_comment"
            i += 2
            continue

        if ch == "/" and nxt == "*":
            state = "block_comment"
            i += 2
            continue

        if ch == "'":
            state = "single_quote"
            i += 1
            continue

        if ch == '"':
            state = "double_quote"
            i += 1
            continue

        if ch in "([{":
            stack.append((ch, line))
        elif ch in ")]}":
            if not stack or stack[-1][0] != pairs[ch]:
                return {
                    "line": line,
                    "message": f"Unmatched '{ch}' in code block",
                }
            stack.pop()

        if ch == "\n":
            line += 1

        i += 1

    if stack:
        opener, opener_line = stack[-1]
        return {
            "line": opener_line,
            "message": f"Unclosed '{opener}' in code block",
        }

    return None


def extract_features(code, language="python"):
    language = resolve_review_language(language)
    num_lines = max(1, len(code.splitlines()))

    if language == "python":
        try:
            tree = ast.parse(code)
            num_funcs = sum(isinstance(node, ast.FunctionDef) for node in ast.walk(tree))
            num_loops = sum(isinstance(node, (ast.For, ast.While)) for node in ast.walk(tree))
            num_ifs = sum(isinstance(node, ast.If) for node in ast.walk(tree))
            num_try = sum(isinstance(node, ast.Try) for node in ast.walk(tree))
        except SyntaxError:
            num_funcs = num_loops = num_ifs = num_try = 0
    else:
        stripped = strip_c_like_comments(code)
        num_funcs = len(FUNCTION_SIGNATURE_PATTERN.findall(stripped))
        num_loops = len(LOOP_PATTERN.findall(stripped))
        num_ifs = len(IF_PATTERN.findall(stripped))
        num_try = len(TRY_PATTERN.findall(stripped))

    return np.array([[num_lines, num_funcs, num_loops, num_ifs, num_try]])


def estimate_confidence(features, issues_count, language, model):
    language = resolve_review_language(language)
    loops = int(features[0][2])
    conditionals = int(features[0][3])

    estimator = None
    if isinstance(model, dict):
        model_map = model.get("models") if isinstance(model.get("models"), dict) else None
        if model_map:
            estimator = model_map.get(language) or model_map.get("python")
        if estimator is None:
            estimator = model.get("model")
    else:
        estimator = model

    if estimator is not None:
        try:
            return round(float(estimator.predict_proba(features)[0][1] * 100), 2)
        except Exception:
            pass

    heuristic_confidence = min(
        95.0,
        float(issues_count * 16 + loops * 10 + conditionals * 4),
    )
    return round(heuristic_confidence, 2)


def review_code(code, model, language="python"):
    language = resolve_review_language(language)
    result = {
        "confidence": 0,
        "syntax_error": False,
        "error_line": None,
        "error_msg": "",
        "issues": [],
        "complexity": 1,
    }
    seen_issues = set()

    def add_issue(name, line, fix):
        issue = (name, int(line or 0), fix)
        if issue not in seen_issues:
            seen_issues.add(issue)
            result["issues"].append(issue)

    tree = None
    if language == "python":
        try:
            tree = ast.parse(code)
        except SyntaxError as exc:
            result["syntax_error"] = True
            result["error_line"] = exc.lineno
            result["error_msg"] = str(exc)
            result["confidence"] = 95
            return result
    else:
        syntax_error = basic_c_like_syntax_error(code)
        if syntax_error:
            result["syntax_error"] = True
            result["error_line"] = syntax_error["line"]
            result["error_msg"] = syntax_error["message"]
            result["confidence"] = 92
            return result

    features = extract_features(code, language)
    loops = int(features[0][2])
    result["complexity"] = max(1, loops)

    if language == "python" and tree is not None:
        for node in ast.walk(tree):
            if isinstance(node, ast.While):
                if isinstance(node.test, ast.Constant) and node.test.value is True:
                    add_issue(
                        "Possible Infinite Loop",
                        node.lineno,
                        "Add a break condition or update the loop predicate.",
                    )

            if isinstance(node, ast.BinOp) and isinstance(node.op, ast.Div):
                if isinstance(node.right, ast.Constant) and node.right.value == 0:
                    add_issue(
                        "Division by zero",
                        node.lineno,
                        "Check the denominator before dividing.",
                    )

            if isinstance(node, ast.Call) and getattr(node.func, "id", "") == "input":
                for parent in ast.walk(tree):
                    if isinstance(parent, (ast.For, ast.While)) and any(
                        child is node for child in ast.walk(parent)
                    ):
                        add_issue(
                            "Input inside loop",
                            node.lineno,
                            "Move input collection outside the loop when possible.",
                        )
                        break

            if isinstance(node, ast.Call) and getattr(node.func, "attr", "") == "sort":
                for parent in ast.walk(tree):
                    if isinstance(parent, (ast.For, ast.While)) and any(
                        child is node for child in ast.walk(parent)
                    ):
                        add_issue(
                            "Sorting inside loop",
                            node.lineno,
                            "Sort once before the loop or use a better data structure.",
                        )
                        break

        for node in ast.walk(tree):
            if isinstance(node, ast.For):
                for child in ast.walk(node):
                    if isinstance(child, (ast.For, ast.While)) and child is not node:
                        add_issue(
                            "Nested loop (possible O(n^2))",
                            child.lineno,
                            "Reduce nested iteration or add indexing/cache-based lookups.",
                        )

            if isinstance(node, ast.FunctionDef):
                has_return = any(isinstance(child, ast.Return) for child in ast.walk(node))
                if not has_return:
                    add_issue(
                        "Function has no return",
                        node.lineno,
                        "Return a value explicitly or make the function's side effects clear.",
                    )

                calls_self = any(
                    isinstance(child, ast.Call) and getattr(child.func, "id", None) == node.name
                    for child in ast.walk(node)
                )
                has_guard = any(isinstance(child, ast.If) for child in ast.walk(node))
                if calls_self and not has_guard:
                    add_issue(
                        "Recursion without base case",
                        node.lineno,
                        "Add a terminating condition before making the recursive call.",
                    )
    else:
        clean_code = strip_c_like_comments(code)
        lines = clean_code.splitlines()
        recent_loop_lines = []

        for lineno, raw_line in enumerate(lines, start=1):
            line = raw_line.strip()
            if not line:
                continue

            recent_loop_lines = [loop_line for loop_line in recent_loop_lines if lineno - loop_line <= 6]
            has_loop = bool(LOOP_PATTERN.search(line))

            if has_loop and recent_loop_lines:
                add_issue(
                    "Nested loop (possible O(n^2))",
                    lineno,
                    "Consider flattening the loops or using a faster lookup structure.",
                )

            if INFINITE_LOOP_PATTERN.search(line):
                add_issue(
                    "Possible Infinite Loop",
                    lineno,
                    "Add a termination condition or break path inside the loop.",
                )

            if DIVISION_BY_ZERO_PATTERN.search(line):
                add_issue(
                    "Division by zero",
                    lineno,
                    "Guard the denominator before dividing.",
                )

            if has_loop:
                recent_loop_lines.append(lineno)

            input_pattern = INPUT_PATTERNS.get(language)
            if input_pattern and input_pattern.search(line) and recent_loop_lines:
                add_issue(
                    "Input inside loop",
                    lineno,
                    "Read input before the loop or buffer it to reduce repeated I/O.",
                )

            sort_pattern = SORT_PATTERNS.get(language)
            if sort_pattern and sort_pattern.search(line) and recent_loop_lines:
                add_issue(
                    "Sorting inside loop",
                    lineno,
                    "Move sorting outside the loop or keep the data structure ordered.",
                )

            if MISSING_SEMICOLON_PATTERN.match(line):
                add_issue(
                    "Possible missing semicolon",
                    lineno,
                    "Terminate the return statement with a semicolon.",
                )

        allocation_pattern = MEMORY_ALLOC_PATTERNS.get(language)
        release_pattern = MEMORY_RELEASE_PATTERNS.get(language)
        if allocation_pattern and allocation_pattern.search(clean_code):
            if not release_pattern or not release_pattern.search(clean_code):
                add_issue(
                    "Possible memory leak",
                    0,
                    "Release allocated memory with the matching cleanup call on every path.",
                )

        if language == "java" and JAVA_RESOURCE_PATTERN.search(clean_code) and not JAVA_CLOSE_PATTERN.search(clean_code):
            add_issue(
                "Resource may not be closed",
                0,
                "Close scanners/readers in a finally block or use try-with-resources.",
            )

        analyze_c_like_functions(lines, add_issue)

    if loops >= 3:
        add_issue(
            "High Time Complexity (TLE risk)",
            0,
            "Reduce loop nesting or use a more efficient algorithm/data structure.",
        )

    result["confidence"] = estimate_confidence(features, len(result["issues"]), language, model)
    return result


def analyze_c_like_functions(lines, add_issue):
    brace_depth = 0
    pending_function = None
    active_functions = []

    def close_completed_functions(current_depth):
        while active_functions and current_depth < active_functions[-1]["body_depth"]:
            function = active_functions.pop()
            finalize_function(function, add_issue)

    for lineno, raw_line in enumerate(lines, start=1):
        line = raw_line.strip()
        if not line:
            continue

        leading_closes = len(line) - len(line.lstrip("}"))
        current_depth = max(0, brace_depth - leading_closes)
        close_completed_functions(current_depth)

        for function in active_functions:
            if re.search(r"\breturn\b", line):
                function["has_return"] = True
            if re.search(r"\b(?:if|switch)\b", line):
                function["has_guard"] = True
            if re.search(rf"\b{re.escape(function['name'])}\s*\(", line):
                function["calls_self"] = True

        if pending_function and "{" in line:
            pending_function["body_depth"] = current_depth + 1
            active_functions.append(pending_function)
            pending_function = None

        match = FUNCTION_SIGNATURE_PATTERN.match(line)
        if match and match.group("return_type") != "void":
            function = {
                "name": match.group("name"),
                "line": lineno,
                "has_return": False,
                "calls_self": False,
                "has_guard": False,
                "body_depth": current_depth + 1,
            }
            if match.group("brace"):
                active_functions.append(function)
            else:
                pending_function = function

        brace_depth += line.count("{") - line.count("}")
        close_completed_functions(brace_depth)

    while active_functions:
        finalize_function(active_functions.pop(), add_issue)


def finalize_function(function, add_issue):
    if not function["has_return"]:
        add_issue(
            "Function may exit without returning a value",
            function["line"],
            "Return a value on every control path for non-void functions.",
        )

    if function["calls_self"] and not function["has_guard"]:
        add_issue(
            "Recursion without base case",
            function["line"],
            "Add a guard condition before the recursive call.",
        )

import ast
import re
from pathlib import Path
from typing import Iterable

import pandas as pd


SUPPORTED_LANGUAGES = {"python", "c", "cpp", "java"}
LANGUAGE_ALIASES = {
    "py": "python",
    "c++": "cpp",
    "cc": "cpp",
    "cxx": "cpp",
    "hpp": "cpp",
    "hxx": "cpp",
}
EXTENSION_TO_LANGUAGE = {
    ".py": "python",
    ".c": "c",
    ".h": "c",
    ".cpp": "cpp",
    ".cc": "cpp",
    ".cxx": "cpp",
    ".hpp": "cpp",
    ".hxx": "cpp",
    ".java": "java",
}


def normalize_language(language: str | None) -> str | None:
    if not language:
        return None
    normalized = str(language).strip().lower()
    return LANGUAGE_ALIASES.get(normalized, normalized)


def infer_language_from_path(path: str | None) -> str | None:
    if not path:
        return None
    ext = Path(path).suffix.lower()
    return EXTENSION_TO_LANGUAGE.get(ext)


def is_valid_python(code: str) -> bool:
    try:
        ast.parse(code)
        return True
    except Exception:
        return False


def _resolve_row_language(row: pd.Series) -> str | None:
    row_lang = normalize_language(row.get("language"))
    if row_lang in SUPPORTED_LANGUAGES:
        return row_lang
    return infer_language_from_path(row.get("path"))


def clean_dataset(df: pd.DataFrame, allowed_languages: Iterable[str] | None = None) -> pd.DataFrame:
    allowed = {normalize_language(lang) for lang in (allowed_languages or SUPPORTED_LANGUAGES)}
    allowed.discard(None)

    cleaned = df.copy()
    cleaned["code"] = cleaned["code"].fillna("").astype(str)
    cleaned = cleaned[cleaned["code"].str.strip().str.len() >= 8]

    cleaned["review_language"] = cleaned.apply(_resolve_row_language, axis=1)
    cleaned = cleaned[cleaned["review_language"].isin(allowed)]

    # Parse validation where we have a reliable parser.
    python_mask = cleaned["review_language"] == "python"
    if python_mask.any():
        cleaned = cleaned[~python_mask | cleaned["code"].apply(is_valid_python)]

    cleaned = cleaned.reset_index(drop=True)
    print("After cleaning:", len(cleaned))
    print("Language distribution after cleaning:")
    print(cleaned["review_language"].value_counts(dropna=False))
    return cleaned


def bug_risk_label(code: str, language: str = "python") -> int:
    language = normalize_language(language) or "python"
    score = 0

    normalized = code.replace(" ", "")

    # Generic risk hints.
    if "TODO" in code or "FIXME" in code:
        score += 1
    if "while(true)" in normalized or "for(;;)" in normalized:
        score += 2
    if re.search(r"/\s*0(?:[^\d.]|$)", code):
        score += 2

    if language == "python":
        if "try:" not in code or "except" not in code:
            score += 1
        if re.search(r"==\s*None", code):
            score += 1
        if "eval(" in code or "exec(" in code:
            score += 2
    elif language in {"c", "cpp"}:
        if re.search(r"\b(?:malloc|calloc|realloc)\s*\(", code) and "free(" not in code:
            score += 2
        if language == "cpp" and "new " in code and "delete " not in code:
            score += 2
        if re.search(r"\bgets\s*\(", code) or re.search(r"\bstrcpy\s*\(", code):
            score += 2
    elif language == "java":
        if re.search(r"\bnew\s+(?:Scanner|BufferedReader)\b", code) and ".close(" not in code:
            score += 2
        if re.search(r"\bcatch\s*\(\s*Exception", code):
            score += 1

    return 1 if score >= 2 else 0

from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from pydantic import BaseModel
from database import get_db
import models
from auth import verify_password, get_password_hash, create_access_token

router = APIRouter(prefix="/api/auth", tags=["auth"])


class SignupRequest(BaseModel):
    email: str
    username: str
    password: str


class LoginRequest(BaseModel):
    email: str
    password: str


@router.post("/signup")
def signup(data: SignupRequest, db: Session = Depends(get_db)):
    if db.query(models.User).filter(models.User.email == data.email).first():
        raise HTTPException(status_code=400, detail="Email already registered")
    if db.query(models.User).filter(models.User.username == data.username).first():
        raise HTTPException(status_code=400, detail="Username already taken")

    user = models.User(
        email=data.email,
        username=data.username,
        hashed_password=get_password_hash(data.password),
    )
    db.add(user)
    db.commit()
    db.refresh(user)

    token = create_access_token({"sub": str(user.id)})
    return {
        "access_token": token,
        "token_type": "bearer",
        "user": {"id": user.id, "email": user.email, "username": user.username},
    }


@router.post("/login")
def login(data: LoginRequest, db: Session = Depends(get_db)):
    user = db.query(models.User).filter(models.User.email == data.email).first()
    if not user or not verify_password(data.password, user.hashed_password):
        raise HTTPException(status_code=401, detail="Invalid email or password")

    token = create_access_token({"sub": str(user.id)})
    return {
        "access_token": token,
        "token_type": "bearer",
        "user": {"id": user.id, "email": user.email, "username": user.username},
    }

